CODE_EXAMPLE:
// Before
class Site {}
class ResidentialSite extends Site {
  Money getBillingAmount() { ... }
}
class LifelineSite extends Site {
  Money getBillingAmount() { ... }
}

// After
abstract class Site {
  Money getBillingAmount() {
    return getBaseAmount() + getDiscountAmount();
  }
  abstract Money getBaseAmount();
  abstract Money getDiscountAmount();
}

UNIT_TEST_EXAMPLE:
@Test
public void testTemplateMethod() {
  Site site = new ResidentialSite();
  Money amount = site.getBillingAmount();
  assertTrue(amount.getValue() > 0);
}
